framework_css:
/*
   Basic academic design system derived from the provided screenshot.
   Early-2000s style: minimal decoration, serif fonts, link-based navigation.
*/

:root {
    /* Color palette */
    --color-link: #0000EE;       /* bright blue links */
    --color-link-visited: #551A8B; /* close to browser default visited purple */
    --color-background-page: #F7F7F7;
    --color-background-panel: #F1D98A; /* warm beige content panel */
    --color-border-soft: #D0D0D0;  /* light grey separators */
    --color-text-main: #000000;

    /* Typography */
    --font-heading: "Times New Roman", Times, serif;
    --font-body: "Times New Roman", Times, serif;
    --font-code: "Courier New", monospace;

    --font-size-h1: 24px;
    --font-size-h2: 20px;
    --font-size-h3: 16px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.4;
    --line-height-relaxed: 1.6;

    /* Spacing scale (4px base unit) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 24px;
    --space-6: 32px;
}

/* Global base styles */

html,
body {
    margin: 0;
    padding: 0;
}

body {
    background-color: var(--color-background-page);
    color: var(--color-text-main);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
}

a {
    color: var(--color-link);
    text-decoration: underline;
}

a:visited {
    color: var(--color-link-visited);
}

a:hover,
a:focus {
    text-decoration: underline;
}

img {
    border: 0;
    max-width: 100%;
}

hr {
    border: none;
    border-top: 1px solid var(--color-border-soft);
    margin: 0;
}

/* Header layout matching design */

.site-header {
    padding: var(--space-4) var(--space-3) 0 var(--space-3);
}

.header-inner {
    max-width: 1100px;
    margin: 0 auto;
}

.logo-title-row {
    display: flex;
    align-items: flex-end;
    justify-content: center; /* center slug + title block within page */
    column-gap: var(--space-3);
}

.logo {
    flex: 0 0 auto;
}

.site-title-wrapper {
    flex: 0 0 auto;
}

.site-title-link {
    font-family: var(--font-heading);
    font-size: var(--font-size-h1);
    font-weight: 700;
    line-height: var(--line-height-tight);
}

.site-intro {
    text-align: center;
    margin-top: var(--space-2);
}

.intro-main-link {
    margin: 0;
    font-weight: 700;
}

.intro-main-link a {
    font-size: var(--font-size-body);
}

.intro-subtitle {
    margin: 0;
    margin-top: var(--space-1);
    font-size: var(--font-size-body);
}

.header-separator {
    margin-top: var(--space-4);
}

/* Primary navigation: simple inline links under header, centered */

.primary-nav {
    margin-top: var(--space-3);
    text-align: center;
    font-size: var(--font-size-small);
}

.primary-nav p {
    margin: 0;
}

.primary-nav a {
    white-space: nowrap;
}

/* Main content area */

#content {
    max-width: 1100px;
    margin: var(--space-4) auto;
    padding: 0 var(--space-3);
}

/* Beige panel used for species and other feature content */

.content-panel {
    background-color: var(--color-background-panel);
    padding: var(--space-3);
    margin-bottom: var(--space-4);
}

.content-panel h1,
.content-panel h2,
.content-panel h3 {
    font-family: var(--font-heading);
}

/* Footer styling based on early academic pages */

.site-footer {
    padding: 0 var(--space-3) var(--space-4) var(--space-3);
}

.footer-inner {
    max-width: 1100px;
    margin: 0 auto;
    text-align: center;
}

.footer-separator {
    margin-top: 0;
    margin-bottom: var(--space-2);
}

.footer-nav {
    font-size: var(--font-size-small);
}

.footer-nav a {
    margin: 0 var(--space-1);
}

.footer-note {
    margin-top: var(--space-2);
    font-size: var(--font-size-small);
}
